// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.scope;

import static org.assertj.core.api.Assertions.assertThat;

import java.lang.reflect.Constructor;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Filter;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.QueryRoot;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.Test;

public class ScopeSafeRewriterTest {

	@Test
	public void filterBelowJoinUsesPrimitiveProofAndLeavesNearestInvalidFormUntouched() throws Exception {
		QueryRoot safeRoot = filteredJoin("leftOnly");
		Object safeRewriter = rewriter(safeRoot);
		boolean accepted = (boolean) safeRewriter.getClass()
				.getDeclaredMethod("moveFilterBelowJoinLeft", Filter.class)
				.invoke(safeRewriter, safeRoot.getArg());
		assertThat(accepted).isTrue();
		assertThat(safeRoot.getArg()).isInstanceOf(Join.class);
		assertThat(((Join) safeRoot.getArg()).getLeftArg()).isInstanceOf(Filter.class);

		QueryRoot deniedRoot = filteredJoin("rightOnly");
		Filter deniedFilter = (Filter) deniedRoot.getArg();
		Object deniedRewriter = rewriter(deniedRoot);
		boolean denied = (boolean) deniedRewriter.getClass()
				.getDeclaredMethod("moveFilterBelowJoinLeft", Filter.class)
				.invoke(deniedRewriter, deniedFilter);
		assertThat(denied).isFalse();
		assertThat(deniedRoot.getArg()).isSameAs(deniedFilter);
	}

	private static QueryRoot filteredJoin(String conditionName) {
		StatementPattern left = pattern("shared", "leftOnly");
		StatementPattern right = pattern("shared", "rightOnly");
		return new QueryRoot(new Filter(new Join(left, right), Var.of(conditionName)));
	}

	private static StatementPattern pattern(String first, String second) {
		return new StatementPattern(Var.of(first),
				Var.of("_p", SimpleValueFactory.getInstance().createIRI("urn:p")), Var.of(second));
	}

	private static Object rewriter(QueryRoot root) throws Exception {
		Class<?> type = Class.forName(
				"org.eclipse.rdf4j.query.algebra.evaluation.optimizer.scope.ScopeSafeRewriter");
		Constructor<?> constructor = type.getDeclaredConstructor(QueryRoot.class);
		constructor.setAccessible(true);
		return constructor.newInstance(root);
	}
}
